import{_ as o,o as a,c,ag as r}from"./chunks/framework.DGzMGr_a.js";const p=JSON.parse('{"title":"浏览器缓存：强缓存 vs 协商缓存","description":"","frontmatter":{"title":"浏览器缓存：强缓存 vs 协商缓存","difficulty":"medium","tags":["浏览器缓存","HTTP","Cache-Control","ETag"],"estimate":20},"headers":[],"relativePath":"domains/browser/qa/qa-03-http-cache.md","filePath":"domains/browser/qa/qa-03-http-cache.md","lastUpdated":1783504823000}'),s={name:"domains/browser/qa/qa-03-http-cache.md"};function l(n,e,t,i,d,h){return a(),c("div",null,[...e[0]||(e[0]=[r('<h1 id="问答-03-进阶-浏览器缓存-强缓存-vs-协商缓存" tabindex="-1">问答 03（进阶）：浏览器缓存：强缓存 vs 协商缓存 <a class="header-anchor" href="#问答-03-进阶-浏览器缓存-强缓存-vs-协商缓存" aria-label="Permalink to &quot;问答 03（进阶）：浏览器缓存：强缓存 vs 协商缓存&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>浏览器 HTTP 缓存分为强缓存和协商缓存。它们的关键字段有哪些？为什么 <code>Cache-Control</code> 的优先级高于 <code>Expires</code>？<code>no-cache</code> 和 <code>no-store</code> 的区别是什么？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>整体流程</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请求前 → 有强缓存？</span></span>\n<span class="line"><span>  是 → 直接使用本地缓存（200 from cache），不发请求</span></span>\n<span class="line"><span>  否 → 发条件请求，带 If-None-Match / If-Modified-Since</span></span>\n<span class="line"><span>        服务器判断资源是否变更</span></span>\n<span class="line"><span>          未变 → 304 Not Modified，用本地缓存 body</span></span>\n<span class="line"><span>          已变 → 200 + 新 body + 新的 ETag / Last-Modified</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>强缓存字段</strong></p><ul><li><strong><code>Expires</code></strong>（HTTP/1.0）：绝对时间点，如 <code>Expires: Thu, 01 Jan 2026 00:00:00 GMT</code>。</li><li><strong><code>Cache-Control</code></strong>（HTTP/1.1，推荐）：相对时间 + 更细的策略。 <ul><li><code>max-age=N</code>：N 秒内新鲜。</li><li><code>s-maxage=N</code>：仅对共享缓存（CDN / 代理）生效。</li><li><code>public</code> / <code>private</code>：允许共享缓存 vs 只允许浏览器缓存。</li><li><code>no-cache</code>：跳过强缓存，<strong>每次都要协商</strong>。</li><li><code>no-store</code>：<strong>完全不存</strong>任何缓存副本。</li><li><code>must-revalidate</code>：过期后必须再验证。</li><li><code>immutable</code>：告诉浏览器「文件永远不变」，连协商都不用做。</li></ul></li></ul><p><strong>为什么 <code>Cache-Control</code> 优先级高于 <code>Expires</code></strong></p><ol><li><code>Expires</code> 是<strong>绝对时间</strong>，依赖客户端本地时钟。用户改系统时间就能让缓存立即过期或永不过期。</li><li><code>Cache-Control: max-age</code> 是<strong>相对时间</strong>，从收到响应那一刻算起，不受时钟影响。</li><li><code>Cache-Control</code> 语义更丰富，覆盖 <code>Expires</code> 所有能力还有更多。</li><li>HTTP/1.1 规范明确规定：<strong>当两者共存时，以 <code>Cache-Control</code> 为准</strong>。</li></ol><p><strong>协商缓存字段</strong></p><ul><li><strong><code>Last-Modified</code> / <code>If-Modified-Since</code></strong>：基于时间戳，精度秒级；对分布式部署或秒内多次修改不友好。</li><li><strong><code>ETag</code> / <code>If-None-Match</code></strong>：内容摘要（一般是哈希或版本号），精度和准确性都更好。 <ul><li><code>ETag</code> 分强 ETag（内容完全相同）和弱 ETag（<code>W/&quot;abc&quot;</code>，语义相同即可）。</li></ul></li></ul><p><strong>两者关系</strong></p><ul><li>服务器通常同时下发 <code>ETag</code> 和 <code>Last-Modified</code>；浏览器请求时把两者一并回传。</li><li>服务器优先看 <code>If-None-Match</code>，其次 <code>If-Modified-Since</code>。</li></ul><p><strong><code>no-cache</code> vs <code>no-store</code></strong></p><ul><li><code>no-cache</code>：<strong>可以缓存，但用之前必须协商</strong>。适合 HTML 主文档。</li><li><code>no-store</code>：<strong>根本不缓存</strong>，请求响应都不写盘。适合银行、隐私接口。</li><li>别混淆：<code>no-cache</code> <strong>不是</strong>「不缓存」。</li></ul><h2 id="追问-1-为什么带-hash-的静态资源可以设-cache-control-max-age-31536000-immutable" tabindex="-1">追问 1：为什么带 hash 的静态资源可以设 <code>Cache-Control: max-age=31536000, immutable</code>？ <a class="header-anchor" href="#追问-1-为什么带-hash-的静态资源可以设-cache-control-max-age-31536000-immutable" aria-label="Permalink to &quot;追问 1：为什么带 hash 的静态资源可以设 `Cache-Control: max-age=31536000, immutable`？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>构建工具（Vite / webpack）会给资源加内容哈希：<code>app.a1b2c3.js</code>。文件名 = 内容摘要，一旦内容变了，URL 就变。</li><li>因此这个 URL 对应的内容<strong>永远不会改变</strong>，可以设一年的强缓存 + <code>immutable</code>。</li><li>部署新版本时 HTML 引用的是新的哈希文件名，旧文件不会被误用。</li><li>HTML 本身则要设 <code>no-cache</code> 或很短的 <code>max-age</code>，保证用户能拿到最新的入口。</li><li>这就是「HTML 短缓存 + 静态资源长缓存」的经典策略。</li></ul><h2 id="追问-2-memory-cache-和-disk-cache-有什么区别-f5-刷新和-ctrl-f5-分别怎么影响缓存" tabindex="-1">追问 2：<code>memory cache</code> 和 <code>disk cache</code> 有什么区别？F5 刷新和 Ctrl+F5 分别怎么影响缓存？ <a class="header-anchor" href="#追问-2-memory-cache-和-disk-cache-有什么区别-f5-刷新和-ctrl-f5-分别怎么影响缓存" aria-label="Permalink to &quot;追问 2：`memory cache` 和 `disk cache` 有什么区别？F5 刷新和 Ctrl+F5 分别怎么影响缓存？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>memory cache</strong>：内存缓存，tab 关掉就没了。命中极快（微秒级），常用于同页面内重复请求同一资源。</li><li><strong>disk cache</strong>：磁盘缓存，跨 tab / 跨会话保留，容量大但读取略慢。</li><li><strong>Service Worker cache</strong>：由 SW 主动写入的 Cache Storage，可离线。</li><li>刷新行为（Chrome）： <ul><li><strong>地址栏回车 / 导航</strong>：正常走缓存策略。</li><li><strong>F5 / 普通刷新</strong>：主文档变成 <code>Cache-Control: max-age=0</code>（等价 <code>no-cache</code>），子资源仍走各自缓存策略。</li><li><strong>Ctrl+F5 / 强制刷新</strong>：所有请求都带 <code>Cache-Control: no-cache</code> 和 <code>Pragma: no-cache</code>，等同于把强缓存跳过；如果 DevTools 里勾了「Disable cache」也是类似效果。</li></ul></li></ul><h2 id="追问-3-cdn-缓存和浏览器缓存怎么协同-s-maxage-有什么用" tabindex="-1">追问 3：CDN 缓存和浏览器缓存怎么协同？<code>s-maxage</code> 有什么用？ <a class="header-anchor" href="#追问-3-cdn-缓存和浏览器缓存怎么协同-s-maxage-有什么用" aria-label="Permalink to &quot;追问 3：CDN 缓存和浏览器缓存怎么协同？`s-maxage` 有什么用？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>请求链路：浏览器 → CDN 边缘节点 → 源站。任意一层都可能缓存。</li><li><code>Cache-Control: max-age=60, s-maxage=3600</code> 表示：<strong>浏览器缓存 60 秒，CDN 缓存 1 小时</strong>。这样源站压力小，用户体感新鲜。</li><li>主动失效：CDN 提供刷新（purge）/ 预热接口；用带 hash 的文件名从根本上避免刷新问题。</li><li><code>Vary</code> 头告诉缓存以哪些请求头作为缓存 key（如 <code>Vary: Accept-Encoding</code> 区分 gzip / br；<code>Vary: Cookie</code> 会让个性化响应无法被公共缓存复用）。</li><li><code>Cache-Control: private</code> 明确禁止 CDN 缓存，避免个人化数据被别人拿到。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://www.rfc-editor.org/rfc/rfc9111.html" target="_blank" rel="noreferrer">RFC 9111: HTTP Caching</a>：缓存控制与验证机制规范</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Caching" target="_blank" rel="noreferrer">MDN: HTTP Caching</a>：强缓存/协商缓存通俗讲解</li><li><a href="https://www.rfc-editor.org/rfc/rfc9110.html" target="_blank" rel="noreferrer">RFC 9110: HTTP Semantics</a>：Cache-Control 等头字段语义</li></ul>',28)])])}const m=o(s,[["render",l]]);export{p as __pageData,m as default};
